      { id: 1004, yearNumeric: -1, yearDisplay: "1 BW", title: "The Four Quests", description: "Prince Haldric asks the Four elvish Lords for help and land. They set before him four quests to prove his worth, which he completes." },
      { id: 1005, yearNumeric: 1, yearDisplay: "1 YW", title: "Founding of Wesnoth", description: "Haldric founds the country of Wesnoth in the central plain south of the great River." },
      { id: 1006, yearNumeric: 1, yearDisplay: "1 YW", title: "The Broken Pact", description: "Haldric agrees to a Pact of Mutual Defence with the elves, but the Ka'lian decides it will betray him. Haldric considers the Pact a dead letter." },
      { id: 1007, yearNumeric: 1, yearDisplay: "1 YW", title: "Reign of Haldric I", description: "Reign of Haldric I (formerly prince Haldric) begins. The Rise of Wesnoth ends." }
